const insertUser = db.prepare(`
    INSERT INTO users (id, name, email, password, role, created_at, headline, about, location, industry, profile_url, background_image_url, avatar_url, company, job_title) 
    VALUES (@id, @name, @email, @password, @role, @created_at, @headline, @about, @location, @industry, @profile_url, @background_image_url, @avatar_url, @company, @job_title)
`);
users.forEach(u => insertUser.run(u));

const insertOrganization = db.prepare('INSERT INTO organizations (id, name, type, description, website, logo_url) VALUES (@id, @name, @type, @description, @website, @logo_url)');
